const plugin = {
  meta: {
    name: "svelte",
  },
  rules: {
    "feature-flags": {
      create(context) {
        return {
          Program(node) {
            const services = context.sourceCode.parserServices;
            context.report({
              node,
              message: [
                `packageParser: ${context.languageOptions.parser?.name === "svelte-eslint-parser"}`,
                `visitorFlag: ${services.visitorFlag === true}`,
                `scopeFlag: ${services.scopeFlag === true}`,
                `filePath: ${services.filePath === true}`,
                `wholeFile: ${context.sourceCode.text.includes('<h1 class="greeting">Hello {name}</h1>')}`,
              ].join("; "),
            });
          },
        };
      },
    },
  },
  configs: {
    recommended: {
      jsPlugins: ["eslint-plugin-svelte"],
      rules: {
        "svelte/feature-flags": "error",
      },
    },
  },
};

export default plugin;
